const item = $('Text Pipeline Input').first().json;
const order = item.order || {};
const jobId = item.jobId || `ft_${Date.now()}`;
const worldLabels = { disney_light: 'теплая романтическая история без магии, с мягким юмором и совместным приключением', adventure_classic: 'классическое приключение с открытиями, смелостью и дружеской динамикой', new_year: 'уютная магическая школа и зимнее приключение без прямого копирования известных франшиз', fantasy_epic: 'эпическое фэнтези с ответственностью, древними местами и ясной ценой выбора', cyberpunk_dream: 'ироничный русский киберпанк 2026 года, городские сервисы, контроль и человеческое тепло' };
const heroes = (order.heroes || []).filter((hero) => hero.name || hero.description || hero.relation).map((hero) => `Герой ${hero.n}: ${hero.name || 'без имени'} - ${hero.description || 'описание не задано'} - ${hero.relation || 'роль не задана'}`).join('\n');
const systemText = 'Ты - автор персональных книг Fairyteller. Пиши на русском языке, без буквы ё. Тон: современная ясная проза, живые сцены, теплые детали, без канцелярита и мета-комментариев. Герои уже заданы пользователем; не меняй имена, факты и отношения. Не добавляй известных copyrighted персонажей и не копируй чужие вселенные. Для романтики держи скромный уровень: близость через поступки, взгляд, заботу и диалог, без эротики. Верни только валидный JSON. Внутри JSON-строк не используй кавычки-елочки, markdown, списки и переносы строк; диалоги оформляй через тире.';
const userText = `Создай story bible и ПЕРВУЮ главу персональной книги. Остальные главы пока не писать полностью: нужен только краткий план 2-5 глав, чтобы первая глава была началом цельной истории.\n\nМир: ${order.world || 'disney_light'} - ${worldLabels[order.world] || 'уютная приключенческая сказка'}\nЛокация: ${order.location || 'не задана'}\nВажный предмет: ${order.artifact || 'не задан'}\nЯзык: ${order.language || 'ru'}\nСтиль иллюстраций: ${order.illustrationStyle || 'storybook'}\n\nПерсонажи:\n${heroes || 'Герои не заданы; создай нейтральную пару/команду без новых анкетных подробностей.'}\n\nТребования к первой главе:\n- Это глава 1 из 5. Она должна работать как быстрый UX-preview, но быть настоящей литературной главой.\n- 5 текстовых блоков для верстки, каждый 520-760 знаков, каждый блок 2-3 абзаца.\n- В главе должны быть: ритуал/контекст героев, толчок к приключению, локация в осязаемых деталях, предмет в действии, мягкий крючок на главу 2.\n- Диалоги короткие, не больше 4-6 реплик на главу.\n- Не используй заголовки внутри textBlocks, markdown, маркеры списков и служебные пометки.\n- Не вставляй переносы строк внутри значений JSON; каждый textBlocks[i] должен быть одной JSON-строкой.\n- chapter1.summary должен быть визуальным ТЗ для иллюстрации: кто в кадре, где, что делает, предмет, свет, ракурс, настроение; 260-380 знаков, без будущих спойлеров и без слов про стиль.\n\nВерни JSON строго по schema.`;
const responseSchema = {
  type: 'OBJECT',
  properties: {
    bookTitle: { type: 'STRING' },
    subtitle: { type: 'STRING' },
    coverSummary: { type: 'STRING' },
    storyBible: {
      type: 'OBJECT',
      properties: {
        world: { type: 'STRING' },
        location: { type: 'STRING' },
        artifact: { type: 'STRING' },
        tone: { type: 'STRING' },
        throughline: { type: 'STRING' },
      },
      required: ['world', 'location', 'artifact', 'tone', 'throughline'],
    },
    chapterPlan: {
      type: 'ARRAY',
      items: {
        type: 'OBJECT',
        properties: {
          n: { type: 'NUMBER' },
          title: { type: 'STRING' },
          beat: { type: 'STRING' },
        },
        required: ['n', 'title', 'beat'],
      },
    },
    chapter1: {
      type: 'OBJECT',
      properties: {
        title: { type: 'STRING' },
        summary: { type: 'STRING' },
        textBlocks: { type: 'ARRAY', items: { type: 'STRING' } },
      },
      required: ['title', 'summary', 'textBlocks'],
    },
  },
  required: ['bookTitle', 'subtitle', 'coverSummary', 'storyBible', 'chapterPlan', 'chapter1'],
};
const geminiRequest = {
  systemInstruction: { parts: [{ text: systemText }] },
  contents: [{ role: 'user', parts: [{ text: userText }] }],
  generationConfig: {
    temperature: 0.65,
    topP: 0.9,
    maxOutputTokens: 6000,
    responseMimeType: 'application/json',
    responseSchema,
  },
};
return [{ json: { ...item, jobId, geminiModel: 'gemini-2.5-flash', geminiRequest }, binary: $('Text Pipeline Input').first().binary }];

const source = $('Build First Chapter Prompt').first().json;
const response = $input.first().json;

function collectText(value) {
  return String(value?.candidates?.[0]?.content?.parts?.map((part) => part.text || '').join('') || '').trim();
}

function extractJsonCandidate(text) {
  let candidate = String(text || '').trim().replace(/^\uFEFF/, '');
  const fence = candidate.match(/^\`\`\`(?:json)?\s*([\s\S]*?)\s*\`\`\`$/i);
  if (fence) candidate = fence[1].trim();
  const firstBrace = candidate.indexOf('{');
  const lastBrace = candidate.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidate = candidate.slice(firstBrace, lastBrace + 1);
  }
  return candidate;
}

function escapeControlCharsInsideStrings(text) {
  let result = '';
  let inString = false;
  let escaped = false;
  for (const char of text) {
    if (escaped) {
      result += char;
      escaped = false;
      continue;
    }
    if (char === '\\') {
      result += char;
      escaped = true;
      continue;
    }
    if (char === '"') {
      inString = !inString;
      result += char;
      continue;
    }
    if (inString && char === '\n') {
      result += '\\n';
      continue;
    }
    if (inString && char === '\r') {
      result += '\\r';
      continue;
    }
    if (inString && char === '\t') {
      result += '\\t';
      continue;
    }
    result += char;
  }
  return result;
}

function parseGeminiJson(raw) {
  const candidate = extractJsonCandidate(raw);
  const attempts = [
    candidate,
    escapeControlCharsInsideStrings(candidate),
  ];
  let lastError;
  for (const attempt of attempts) {
    try {
      return JSON.parse(attempt);
    } catch (error) {
      lastError = error;
    }
  }
  throw new Error(`Gemini first chapter response was not valid JSON after repair: ${lastError?.message || 'unknown parse error'}`);
}

const rawText = collectText(response);
if (!rawText) throw new Error('Gemini first chapter response was empty');
const generated = parseGeminiJson(rawText);
const chapter1 = generated.chapter1 || {};
const textBlocks = Array.isArray(chapter1.textBlocks)
  ? chapter1.textBlocks.map((block) => String(block || '').replace(/\s+/g, ' ').trim()).filter(Boolean)
  : [];
if (textBlocks.length !== 5) throw new Error(`Expected 5 chapter 1 text blocks, got ${textBlocks.length}`);
const fullChapterText = textBlocks.join('\n\n');
const preview = {
  chapter: 1,
  title: chapter1.title || generated.bookTitle || 'Первая глава',
  summary: chapter1.summary || '',
  text: fullChapterText,
  imageStatus: 'pending',
};
const text = {
  bible: {
    ...(generated.storyBible || {}),
    world: generated.storyBible?.world || source.order?.world || '',
    location: generated.storyBible?.location || source.order?.location || '',
    artifact: generated.storyBible?.artifact || source.order?.artifact || '',
    bookTitle: generated.bookTitle || '',
    subtitle: generated.subtitle || '',
    coverSummary: generated.coverSummary || '',
    chapterPlan: generated.chapterPlan || [],
  },
  preview,
  chapters: [{ n: 1, title: preview.title, summary: preview.summary, textBlocks, text: fullChapterText, status: 'ready' }],
  generation: { provider: 'gemini', model: source.geminiModel || 'gemini-2.5-flash', responseId: response.responseId || null },
};
return [{ json: { ...source, status: 'chapter_1_ready', text, pipeline: { next: 'fairyteller_visuals', previewEnabled: true, firstChapterImagePriority: true } }, binary: $('Build First Chapter Prompt').first().binary }];
